import{c as s,Q as n,j as a,m as e}from"./chunks/framework.Bhbi9jCp.js";const g=JSON.parse('{"title":"Tick 系统:20 TPS 主循环与三类更新","description":"","frontmatter":{},"headers":[],"relativePath":"minecraftLearning/04-Tick系统-20TPS主循环与三类更新.md","filePath":"minecraftLearning/04-Tick系统-20TPS主循环与三类更新.md","lastUpdated":1781674740000}'),i={name:"minecraftLearning/04-Tick系统-20TPS主循环与三类更新.md"};function o(p,t,c,l,r,d){return n(),a("div",null,[...t[0]||(t[0]=[e(`<h1 id="tick-系统-20-tps-主循环与三类更新" tabindex="-1">Tick 系统:20 TPS 主循环与三类更新 <a class="header-anchor" href="#tick-系统-20-tps-主循环与三类更新" aria-label="Permalink to &quot;Tick 系统:20 TPS 主循环与三类更新&quot;">​</a></h1><p>一个&quot;无限大、处处可交互&quot;的世界,凭什么能在一台普通机器上跑得动?如果每一帧都把世界里上亿个方块、成百上千个实体全算一遍,任何硬件都会瞬间跪下。Minecraft 给出的答案不是&quot;算得更快&quot;,而是<strong>算得更省</strong>:用一个固定频率的逻辑循环驱动整个世界,并且把&quot;哪些方块需要被更新&quot;这件事拆成三套完全不同的机制,让绝大多数方块在绝大多数时间里<strong>根本不被碰</strong>。</p><p>这一篇讲清楚:世界是怎么&quot;动&quot;起来的,以及为什么你看到的水流、作物生长、红石信号,背后是三种截然不同的更新路径。</p><blockquote><p>一句话先记住:<strong>Minecraft 世界按固定 20 tick/秒推进;方块更新分三类——计划刻(排队的延迟任务)、随机刻(每区块抽样的缓慢演化)、邻居通知(事件驱动的即时级联),三者各管一摊,合起来才让&quot;省&quot;成为可能。</strong></p></blockquote><hr><h2 id="一、基本节奏-20-tps-和帧率没关系" tabindex="-1">一、基本节奏:20 TPS,和帧率没关系 <a class="header-anchor" href="#一、基本节奏-20-tps-和帧率没关系" aria-label="Permalink to &quot;一、基本节奏:20 TPS,和帧率没关系&quot;">​</a></h2><p>游戏世界以固定 <strong>20 tick/秒</strong> 推进,一个 tick 名义上 <strong>50 毫秒</strong>。这里第一个反直觉点:</p><blockquote><p><strong>逻辑时钟(TPS)和渲染时钟(FPS)是两套独立的东西。</strong></p></blockquote><ul><li>你的显卡可以跑 144 FPS,但游戏逻辑永远只按 20 TPS 走。</li><li>渲染之所以看起来流畅,是客户端在两个 tick 状态之间做<strong>插值(interpolation)</strong>,把 50ms 的逻辑步长&quot;抹&quot;成连续画面。</li><li>所以&quot;掉帧&quot;和&quot;掉 TPS&quot;是两码事:前者是画面卡,后者是<strong>整个世界变慢</strong>——怪物动得慢、作物长得慢、红石变迟钝。</li></ul><p>一个 tick 名义上要在 50ms 内做完一整轮世界更新。做完了,就睡到下一个 50ms 边界;做不完,麻烦就来了。</p><hr><h2 id="二、主循环-一个时间累加器" tabindex="-1">二、主循环:一个时间累加器 <a class="header-anchor" href="#二、主循环-一个时间累加器" aria-label="Permalink to &quot;二、主循环:一个时间累加器&quot;">​</a></h2><p>服务端核心是一个 <code>while (running)</code> 死循环(<code>MinecraftServer.runServer</code> / <code>tickServer</code>),计时逻辑本质是一个<strong>时间累加器</strong>:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>long lastTime = 系统毫秒</span></span>
<span class="line"><span>while (running) {</span></span>
<span class="line"><span>    long now = 系统毫秒</span></span>
<span class="line"><span>    accumulator += (now - lastTime)   // 累计&quot;欠&quot;了多少时间</span></span>
<span class="line"><span>    lastTime = now</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    while (accumulator &gt;= 50) {        // 每欠够 50ms,就跑一个 tick</span></span>
<span class="line"><span>        accumulator -= 50</span></span>
<span class="line"><span>        tick()                          // 跑一整轮世界更新</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>    睡到下一个 50ms 边界</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>关键推论:</p><ul><li><p><strong>单 tick 算不完会&quot;拖时&quot;。</strong> 如果某次 <code>tick()</code> 耗了 80ms,下一轮循环发现 <code>accumulator</code> 已经欠了不止一个 tick,于是会<strong>连跑多个 tick 追赶</strong>。</p></li><li><p><strong>但追赶有上限。</strong> 当欠账太多(累计超过约 2000ms,即落后约 40 个 tick),服务端会<strong>直接丢弃</strong>这部分时间并打印:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Can&#39;t keep up! Running 2150ms (43 ticks) behind, skipping 43 tick(s)</span></span></code></pre></div></li><li><p>所以 <strong>TPS 掉到 15</strong> 的真实含义不是&quot;时间被放慢了&quot;,而是<strong>单个 tick 里要干的活超过了 50ms 预算,导致追不上墙钟时间</strong>。世界整体变慢,是这个的副作用。</p></li></ul><blockquote><p>1.21 引入的 <code>/tick freeze</code>、<code>/tick rate</code>、<code>/tick step</code>,本质就是直接干预上面这个累加器和目标步长——冻结即停止推进 <code>accumulator</code>,变速即修改那个 <code>50</code>。</p></blockquote><hr><h2 id="三、一个-tick-里到底做了什么" tabindex="-1">三、一个 tick 里到底做了什么 <a class="header-anchor" href="#三、一个-tick-里到底做了什么" aria-label="Permalink to &quot;三、一个 tick 里到底做了什么&quot;">​</a></h2><p>每个已加载维度(主世界 / 下界 / 末地)每 tick 大致按这个顺序走一遍:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 世界边界、天气、时间推进</span></span>
<span class="line"><span>2. tickPending     —— 处理到期的 scheduled block tick 和 fluid tick(两个独立队列)</span></span>
<span class="line"><span>3. 遍历需 tick 的 chunk:</span></span>
<span class="line"><span>     · random tick(随机刻)</span></span>
<span class="line"><span>     · 冰雪结冻、雷击、刷怪(mob spawning)</span></span>
<span class="line"><span>4. tickBlockEntities —— 遍历所有方块实体(漏斗/熔炉/刷怪笼…)逐个调 ticker</span></span>
<span class="line"><span>5. 实体 tick         —— 移动、AI、碰撞、计时</span></span>
<span class="line"><span>6. 区块加载 / 卸载、ticket 过期处理</span></span>
<span class="line"><span>7. 网络:把本 tick 的变更打包发给客户端</span></span></code></pre></div><p>注意第 4 步是<strong>线性遍历所有方块实体</strong>的。这就是为什么<strong>漏斗一多就卡</strong>:每个漏斗每隔几 tick 都要做容器检查与物品搬运,数量上去后直接吃满 tick 预算。</p><p>下面三节,分别拆开第 2、3 步里那三类截然不同的更新机制。</p><hr><h2 id="四、scheduled-tick-计划刻-排队的延迟任务" tabindex="-1">四、Scheduled Tick(计划刻):排队的延迟任务 <a class="header-anchor" href="#四、scheduled-tick-计划刻-排队的延迟任务" aria-label="Permalink to &quot;四、Scheduled Tick(计划刻):排队的延迟任务&quot;">​</a></h2><p>很多方块行为是&quot;现在登记,未来某 tick 再执行&quot;。方块<strong>主动注册</strong>一个计划任务,这就是 scheduled tick(也叫 block tick)。</p><p>每个世界维护一个计划刻列表(<code>LevelTicks</code>,旧称 <code>ServerTickList</code>),每条记录概念上是:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{ pos: 方块坐标, type: 方块/流体种类, triggerTick: 第几个 tick 执行, priority: 优先级 }</span></span></code></pre></div><ul><li>内部按 <code>(triggerTick, priority)</code> 排序;每 tick 弹出所有&quot;到期且属于已加载 chunk&quot;的项执行。</li><li><strong>优先级 TickPriority</strong> 取值 -3 ~ +3,用来打破&quot;同一 tick 内谁先谁后&quot;的平局——某些红石元件靠它保证确定性行为。</li><li><strong>每 tick 处理上限约 65536 条</strong>:超出的留到下一 tick,防止一次性爆掉。</li></ul><h3 id="水流扩散-计划刻的完整例子" tabindex="-1">水流扩散:计划刻的完整例子 <a class="header-anchor" href="#水流扩散-计划刻的完整例子" aria-label="Permalink to &quot;水流扩散:计划刻的完整例子&quot;">​</a></h3><p>水有 <strong>level 0–7</strong> 的流动等级(源是特殊标记,流动水离源越远 level 越大)。放下一个水源后发生的事:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>水源放下</span></span>
<span class="line"><span>  → 给四个水平邻居 + 正下方各排一个 fluid tick(主世界水延迟 5 tick)</span></span>
<span class="line"><span>  → 到期:邻居变成 level=1 的流动水,并继续向外排下一圈(再 +5 tick)</span></span>
<span class="line"><span>  → 到期:level=2 …… 一圈一圈推进</span></span>
<span class="line"><span>  → 遇到向下:优先向下流,且竖直水柱 level 不衰减(从上灌到底都是满的)</span></span>
<span class="line"><span>  → 寻路找洞:有一段逻辑会朝&quot;最近能向下掉&quot;的方向优先铺,所以水会绕着流向坑</span></span>
<span class="line"><span>  → 到 level 7 仍未到边界则停止</span></span></code></pre></div><p>所以你肉眼看到的&quot;水慢慢摊开&quot;,本质是<strong>一圈一圈的计划刻级联</strong>,每圈带 5 tick 的视觉延迟。岩浆同理但延迟更长(主世界 30 tick、下界 10 tick),所以岩浆流得明显慢。红石中继器的延迟、TNT 引信、活板门关闭,走的也都是这套队列。</p><hr><h2 id="五、random-tick-随机刻-抽样驱动的缓慢演化" tabindex="-1">五、Random Tick(随机刻):抽样驱动的缓慢演化 <a class="header-anchor" href="#五、random-tick-随机刻-抽样驱动的缓慢演化" aria-label="Permalink to &quot;五、Random Tick(随机刻):抽样驱动的缓慢演化&quot;">​</a></h2><p>环境的&quot;慢慢变化&quot;——作物生长、树苗长树、草蔓延、树叶腐烂、冰雪融化——来自随机刻。它的算法是整套 tick 系统里<strong>最容易被误解</strong>的部分。</p><p>对每个<strong>正在 tick 的 chunk</strong>,遍历它的每个 16×16×16 的 <strong>section</strong>,做 <code>randomTickSpeed</code> 次(游戏规则,<strong>默认 3</strong>):</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>重复 randomTickSpeed 次:</span></span>
<span class="line"><span>    int r = random.nextInt()          // 取一个随机数</span></span>
<span class="line"><span>    int x =  r        &amp; 15</span></span>
<span class="line"><span>    int y = (r &gt;&gt; 8)  &amp; 15</span></span>
<span class="line"><span>    int z = (r &gt;&gt; 16) &amp; 15            // 用位运算从 4096 格里挑一个坐标</span></span>
<span class="line"><span>    BlockState s = section.getBlockState(x, y, z)</span></span>
<span class="line"><span>    if (s.isRandomlyTicking())        // 只有&quot;关心随机刻&quot;的方块才有反应</span></span>
<span class="line"><span>        s.randomTick(...)</span></span></code></pre></div><p>几个要点,每一个都很反直觉:</p><ul><li><strong>抽中但方块不在乎随机刻(石头、泥土)→ 什么都不做。</strong> 这次抽样就浪费了。所以一个 section 里随机刻方块越稀疏,单株被点到的概率越低、生长越慢。</li><li><strong>单株作物的成熟时间是概率分布,不是定值。</strong> 某株作物每 tick 被选中的概率约 <code>3 / 4096</code>,期望约 1365 tick(~68 秒)被点一次——但这是<strong>几何分布</strong>,方差很大。这正是&quot;同一块地里的麦子,有的先熟有的后熟&quot;的根本原因:纯粹看它什么时候被随机点到。</li><li><strong><code>randomTickSpeed</code> 调高是线性加速</strong>:调到几千,植物秒长——但 CPU 负担同步线性上升,而且随机刻还驱动着树叶腐烂、火焰蔓延等,调太高会引发连锁负载甚至卡服。</li></ul><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─ section (16³ = 4096 格) ──────────────┐</span></span>
<span class="line"><span>│  每 tick 随机点名 3 个格子(默认)        │</span></span>
<span class="line"><span>│     · 点到石头 → 浪费                    │</span></span>
<span class="line"><span>│     · 点到麦子 → 生长一阶段              │</span></span>
<span class="line"><span>│  → 所以&quot;被点到&quot;是个掷骰子事件,           │</span></span>
<span class="line"><span>│    地块成熟参差不齐是必然,不是 bug       │</span></span>
<span class="line"><span>└────────────────────────────────────────┘</span></span></code></pre></div><hr><h2 id="六、block-update-邻居通知-事件驱动的即时级联" tabindex="-1">六、Block Update(邻居通知):事件驱动的即时级联 <a class="header-anchor" href="#六、block-update-邻居通知-事件驱动的即时级联" aria-label="Permalink to &quot;六、Block Update(邻居通知):事件驱动的即时级联&quot;">​</a></h2><p>前两类是&quot;排队&quot;和&quot;抽样&quot;,第三类完全不同:它是<strong>事件驱动、当 tick 就传播</strong>的。</p><p>当一个方块状态改变时,会<strong>立即同步通知周围方块</strong>&quot;我变了,你重算一下&quot;。引擎里其实分两支:</p><table tabindex="0"><thead><tr><th>机制</th><th>触发</th><th>典型场景</th></tr></thead><tbody><tr><td><code>neighborChanged</code>(邻居更新)</td><td>邻居方块<strong>状态</strong>变了</td><td>红石信号、铁轨、活塞响应、BUD</td></tr><tr><td><code>updateShape</code>(形状更新)</td><td>邻居<strong>形状/朝向</strong>变了</td><td>楼梯/栅栏调整连接外观;草、火把失去附着方块而掉落</td></tr></tbody></table><p>这套机制的特点是<strong>会级联</strong>:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>A 被改变</span></span>
<span class="line"><span>  → 通知邻居 B 重算</span></span>
<span class="line"><span>     → B 状态变了</span></span>
<span class="line"><span>        → 再通知 C</span></span>
<span class="line"><span>           → …… 当前 tick 内一路传播下去</span></span></code></pre></div><p>红石电路就是利用这种级联来传播信号;沙子/沙砾检测到下方变空气而开始下落、活塞被供能伸出,也都走这条路。设计不当时会引发&quot;更新风暴&quot;——一次改动触发海量连锁更新,瞬间吃满 tick。</p><p><code>world.setBlock(...)</code> 默认带一组 <strong>flag 位</strong>,控制这次放置要不要通知邻居、要不要重渲染、要不要触发 observer。这些 flag 正是各种红石技术(尤其&quot;无更新放置&quot;)的底层抓手。</p><h3 id="顺带-两个-特性级-bug" tabindex="-1">顺带:两个&quot;特性级&quot; bug <a class="header-anchor" href="#顺带-两个-特性级-bug" aria-label="Permalink to &quot;顺带:两个&quot;特性级&quot; bug&quot;">​</a></h3><ul><li><strong>quasi-connectivity(准连接)</strong>:活塞、漏斗等设备不仅检查自身是否被供能,<strong>还检查正上方一格</strong>是否被供能(历史遗留逻辑)。这导致&quot;隔空供能&quot;现象,大量红石机器依赖它。Java 版保留、基岩版没有——这是两版红石电路不通用的主因之一。</li><li><strong>0-tick</strong>:利用&quot;同一 tick 内更新顺序 + 计划刻尚未结算&quot;的时间窗,在一个 tick 内对作物做多次生长触发,或让活塞零延迟伸缩。本质是钻 update 顺序的空子,部分已被官方修掉。</li></ul><hr><h2 id="七、三类更新对照" tabindex="-1">七、三类更新对照 <a class="header-anchor" href="#七、三类更新对照" aria-label="Permalink to &quot;七、三类更新对照&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>计划刻 Scheduled</th><th>随机刻 Random</th><th>邻居通知 Block Update</th></tr></thead><tbody><tr><td>触发方式</td><td>主动注册、到期执行</td><td>每 section 每 tick 抽样</td><td>方块改变时事件触发</td></tr><tr><td>时机</td><td>未来某 tick</td><td>当前 tick(被抽中)</td><td>当前 tick(同步级联)</td></tr><tr><td>数据结构</td><td>按时间排序的队列</td><td>位运算随机抽坐标</td><td>直接调用、可递归</td></tr><tr><td>典型用途</td><td>水流/岩浆/红石延迟/TNT</td><td>作物/树/草/腐烂/融冰</td><td>红石/沙子下落/活塞</td></tr><tr><td>开销特征</td><td>只发生在登记过的方块</td><td>与加载体积线性相关</td><td>可级联成更新风暴</td></tr></tbody></table><p><strong>反直觉小结:</strong></p><ul><li>水&quot;慢慢流&quot;不是动画,是计划刻一圈圈排队(每圈 5 tick)。</li><li>作物&quot;参差成熟&quot;不是 bug,是随机抽样的几何分布。</li><li>红石&quot;瞬间响应&quot;是当 tick 同步级联,和前两者完全不是一套机制。</li><li>TPS 掉了不是&quot;时间被调慢&quot;,是单 tick 算不完追不上墙钟。</li></ul><hr><h2 id="八、串联" tabindex="-1">八、串联 <a class="header-anchor" href="#八、串联" aria-label="Permalink to &quot;八、串联&quot;">​</a></h2><p>本篇讲的是&quot;世界怎么动&quot;。但有一个前提没展开:<strong>哪些 chunk 才会被 tick?</strong> random tick、刷怪、流体更新只发生在&quot;正在模拟&quot;的区块里——这由 chunk 的 ticket 等级和 simulation distance 决定,也正是&quot;为什么你一走远,远处的农场和红石机器就停摆&quot;的答案。这部分留到下一篇《区块的生命:加载、ticket 等级与模拟距离》。</p><p>而第 4 步遍历的实体 tick(移动、AABB 碰撞、A* 寻路、AI),是 tick 预算里最贵、最容易拖垮 TPS 的一块,单独放到《实体系统》篇展开。</p><p>把本篇接回贯穿全系列的主线——<strong>&quot;能算不存、能享不复制&quot;</strong>:tick 系统是这条主线在&quot;时间维度&quot;上的体现。它没有为每个方块维护一个&quot;下次更新时间&quot;,而是用<strong>计划刻队列(只为需要的方块排队)+ 随机刻抽样(用概率代替逐个轮询)</strong> 两招,把&quot;遍历整个世界&quot;这件不可能的事,变成了&quot;只碰极少数真正在变化的方块&quot;。省,从来都是设计出来的。</p>`,62)])])}const k=s(i,[["render",o]]);export{g as __pageData,k as default};
